import { createUser, updateUser } from './src/handler.js';
import { validateCreateUser, validateEmail } from './src/validator.js';
import assert from 'node:assert/strict';

// Validator tests
assert.equal(validateEmail('user@example.com'), true);
assert.equal(validateEmail('user@sub.domain.com'), true);
assert.equal(validateEmail('notanemail'), false);
assert.equal(validateEmail(''), false);
assert.equal(validateEmail('@domain.com'), false);
assert.equal(validateEmail('user@'), false);

const valid = validateCreateUser({ name: 'Alice', email: 'alice@example.com' });
assert.equal(valid.valid, true);
assert.deepEqual(valid.errors, []);

const noName = validateCreateUser({ email: 'test@test.com' });
assert.equal(noName.valid, false);
assert.ok(noName.errors.some(e => e.toLowerCase().includes('name')));

const noEmail = validateCreateUser({ name: 'Bob' });
assert.equal(noEmail.valid, false);
assert.ok(noEmail.errors.some(e => e.toLowerCase().includes('email')));

const badEmail = validateCreateUser({ name: 'Charlie', email: 'notvalid' });
assert.equal(badEmail.valid, false);
assert.ok(badEmail.errors.some(e => e.toLowerCase().includes('email')));

const empty = validateCreateUser({});
assert.equal(empty.valid, false);
assert.ok(empty.errors.length >= 2);

// Handler still works
const user = createUser({ name: 'Test', email: 'test@test.com' });
assert.equal(user.name, 'Test');
assert.equal(user.email, 'test@test.com');
assert.ok(user.id);
assert.ok(user.createdAt);

const updated = updateUser(user, { name: 'Updated' });
assert.equal(updated.name, 'Updated');
assert.equal(updated.email, 'test@test.com');
assert.ok(updated.updatedAt);

console.log('All tests passed');
